  await input.simulateKeyboardTap('a', modKey);
  await delay(200);
  await input.simulateKeyboardTap('b', modKey);
  await delay(200);

  // 3. 设置居中
  await input.simulateKeyboardTap('e', modKey);
  await delay(200);

  // 4. 移动到行尾，换行
